func (c *core) afterHooks(resp *Response) error {
	c.client.mu.Lock()
	defer c.client.mu.Unlock()

	for _, f := range c.client.builtinResponseHooks {
		err := f(c.client, resp, c.req)
		if err != nil {
			return err
		}
	}

	for _, f := range c.client.userResponseHooks {
		err := f(c.client, resp, c.req)
		if err != nil {
			return err
		}
	}

	return nil
}
